    CreatorRequestId,
    RuleType,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=global_aws_config(),
)
    return route53resolver(
        "CreateResolverRule",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "CreatorRequestId" => CreatorRequestId, "RuleType" => RuleType
